	for x in range(startSlot, endSlot):
		base_path='/'.join(tagPath.split('/')[:-2])
		base_list=[
		base_path + "/data/Alarm" + str(x) + ".Enabled"
		]
		response=system.tag.writeAsync(base_list,[doEnable])	

if initialChange:
	 updateEnable(1,currentValue.value+1,True)	

elif previousValue.value < currentValue.value:
	 updateEnable(previousValue.value,currentValue.value+1,True)	

elif initialChange or previousValue.value > currentValue.value:
	 updateEnable(currentValue.value+1,previousValue.value+1,False)
